import anthropic, json

client = anthropic.Anthropic()

tools = [{
    "name": "get_current_time",
    "description": "Get the current UTC time as an ISO 8601 string.",
    "input_schema": {"type": "object", "properties": {}, "required": []}
}]

def get_current_time() -> str:
    from datetime import datetime, timezone
    return datetime.now(timezone.utc).isoformat()

messages = [{"role": "user", "content": "What time is it right now?"}]

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=512,
    tools=tools,
    messages=messages
)

print(response.stop_reason)   # "tool_use"
for block in response.content:
    print(block.type)         # "tool_use"
    if block.type == "tool_use":
        print(block.id)       # "toolu_01AbcXyz..."
        print(block.name)     # "get_current_time"
        print(block.input)    # {}

# Claude may return MULTIPLE tool_use blocks in one response
# when it determines that several tools can be called simultaneously.

tools = [
    {
        "name": "get_stock_price",
        "description": "Get the current stock price for a ticker symbol.",
        "input_schema": {
            "type": "object",
            "properties": {
                "ticker": {"type": "string", "description": "Stock ticker, e.g. AAPL"}
            },
            "required": ["ticker"]
        }
    },
    {
        "name": "get_company_info",
        "description": "Get a brief description and sector for a company by ticker.",
        "input_schema": {
            "type": "object",
            "properties": {
                "ticker": {"type": "string"}
            },
            "required": ["ticker"]
        }
    }
]

messages = [{"role": "user", "content": "Tell me about Apple — price and company info"}]
response = client.messages.create(
    model="claude-sonnet-4-6", max_tokens=1024, tools=tools, messages=messages
)

# response.content may contain TWO tool_use blocks
messages.append({"role": "assistant", "content": response.content})

results = []
for block in response.content:
    if block.type == "tool_use":
        if block.name == "get_stock_price":
            output = json.dumps(get_stock_price(**block.input))
        elif block.name == "get_company_info":
            output = json.dumps(get_company_info(**block.input))
        else:
            output = json.dumps({"error": "unknown tool"})

        results.append({
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": output
        })

# All results go in a single user message — one per tool_use block
messages.append({"role": "user", "content": results})

# Signal tool failure by setting is_error: True in the tool_result
try:
    output = json.dumps(get_stock_price(ticker=block.input["ticker"]))
    error = False
except Exception as exc:
    output = str(exc)
    error = True

results.append({
    "type": "tool_result",
    "tool_use_id": block.id,
    "content": output,
    "is_error": error       # Claude sees this and explains the failure
})

def run_tool_loop(user_message: str, tools: list, registry: dict) -> str:
    """Complete tool invocation loop: handles parallel calls, errors, multi-turn."""
    messages = [{"role": "user", "content": user_message}]
    MAX_TURNS = 10

    for _ in range(MAX_TURNS):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            tools=tools,
            messages=messages
        )

        if response.stop_reason == "end_turn":
            return next(
                (b.text for b in response.content if hasattr(b, "text")),
                ""
            )

        messages.append({"role": "assistant", "content": response.content})

        results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            fn = registry.get(block.name)
            if fn is None:
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": f"Unknown tool: {block.name}",
                    "is_error": True
                })
                continue
            try:
                output = json.dumps(fn(**block.input))
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": output
                })
            except Exception as exc:
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": str(exc),
                    "is_error": True
                })

        messages.append({"role": "user", "content": results})

    return "Agent reached maximum turns without completing."

