import signal, json

class ToolTimeoutError(Exception):
    pass

def call_with_timeout(fn, kwargs: dict, timeout_seconds: int = 10):
    def handler(signum, frame):
        raise ToolTimeoutError(f"Tool timed out after {timeout_seconds}s")

    signal.signal(signal.SIGALRM, handler)
    signal.alarm(timeout_seconds)
    try:
        return fn(**kwargs)
    finally:
        signal.alarm(0)  # cancel alarm

def dispatch_with_timeout(block, registry: dict, timeout: int = 10) -> dict:
    fn = registry.get(block.name)
    if fn is None:
        return {"type": "tool_result", "tool_use_id": block.id,
                "content": f"Unknown tool: {block.name}", "is_error": True}
    try:
        result = call_with_timeout(fn, block.input, timeout)
        return {"type": "tool_result", "tool_use_id": block.id,
                "content": json.dumps(result)}
    except ToolTimeoutError as e:
        return {"type": "tool_result", "tool_use_id": block.id,
                "content": str(e), "is_error": True}
    except Exception as e:
        return {"type": "tool_result", "tool_use_id": block.id,
                "content": str(e), "is_error": True}

import time, json

def dispatch_with_retry(block, registry: dict, max_retries: int = 2) -> dict:
    """Retry transient tool failures with exponential backoff."""
    fn = registry.get(block.name)
    if fn is None:
        return {"type": "tool_result", "tool_use_id": block.id,
                "content": f"Unknown tool: {block.name}", "is_error": True}

    last_error = None
    for attempt in range(max_retries + 1):
        try:
            result = fn(**block.input)
            return {"type": "tool_result", "tool_use_id": block.id,
                    "content": json.dumps(result)}
        except ConnectionError as e:
            last_error = e
            if attempt < max_retries:
                time.sleep(2 ** attempt)   # 1s, 2s, 4s, ...
        except Exception as e:
            # Non-transient errors fail immediately
            return {"type": "tool_result", "tool_use_id": block.id,
                    "content": str(e), "is_error": True}

    return {"type": "tool_result", "tool_use_id": block.id,
            "content": f"Failed after {max_retries + 1} attempts: {last_error}",
            "is_error": True}
